import{_ as d,o as a,c as e,ag as r}from"./chunks/framework.CNG7EpJN.js";const b=JSON.parse('{"title":"AIアシスタント","description":"","frontmatter":{"title":"AIアシスタント"},"headers":[],"relativePath":"tenant/14-ai.md","filePath":"tenant/14-ai.md"}'),o={name:"tenant/14-ai.md"};function i(l,t,n,h,s,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_14-aiアシスタント" tabindex="-1">14. AIアシスタント <a class="header-anchor" href="#_14-aiアシスタント" aria-label="Permalink to &quot;14. AIアシスタント&quot;">​</a></h1><p>AIアシスタントは、店舗運営の補助として、投稿文作成、売上分析、競合調査、需要予測、メニュー質問対応などを行います。</p><h2 id="主な機能" tabindex="-1">主な機能 <a class="header-anchor" href="#主な機能" aria-label="Permalink to &quot;主な機能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>内容</th></tr></thead><tbody><tr><td>SNS投稿作成</td><td>メニューやキャンペーンに合わせた投稿文を作成</td></tr><tr><td>売上分析</td><td>売上傾向や改善のヒントを提示</td></tr><tr><td>競合調査</td><td>周辺店舗情報を参考に差別化案を提示</td></tr><tr><td>需要予測</td><td>過去傾向から仕込みや発注の参考値を提示</td></tr><tr><td>AIウェイター</td><td>お客様からのメニュー質問に回答</td></tr><tr><td>予約AI解析</td><td>予約フォームの自由文から日時・人数を自動抽出</td></tr><tr><td>AIシェフ</td><td>KDS の提供優先度を AI がアシスト</td></tr></tbody></table><h2 id="利用時の注意" tabindex="-1">利用時の注意 <a class="header-anchor" href="#利用時の注意" aria-label="Permalink to &quot;利用時の注意&quot;">​</a></h2><p>AIの回答は店舗運営を補助する参考情報です。価格、在庫、営業時間、アレルギー、予約可否など、お客様に影響する内容は必ず店舗側で最終確認してください。</p><div class="tip custom-block"><p class="custom-block-title">操作で困ったときは「サポートガイド」</p><p>管理画面右下の「📚 サポートガイド」ボタンから、FAQ、キーワード検索、症状別の案内、エラー番号検索を利用できます。操作方法を確認したいときは、まずサポートガイドをご利用ください。</p></div><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>AIが利用できない</td><td>時間を置いて再試行し、続く場合はPOSLAサポートへお問い合わせください。</td></tr><tr><td>回答が店舗状況と違う</td><td>店舗側の最新情報を優先してください。</td></tr><tr><td>音声入力が使えない</td><td>Google Chromeとマイク許可を確認してください。</td></tr><tr><td>予約日時の解釈が違う</td><td>「2026年4月25日 19時」のように具体的に入力してください。</td></tr><tr><td>管理画面の操作で困った</td><td>右下の「📚 サポートガイド」から FAQ / キーワード / 症状別に確認できます。</td></tr></tbody></table>',9)])])}const p=d(o,[["render",i]]);export{b as __pageData,p as default};
